import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
// In your Footer.js component
const Footer = () => {
  return (
    <footer>
      <div className="footer-links">
        <a href="/about.html"><i className="fas fa-info-circle"></i> About</a>
        <a href="/terms.html"><i className="fas fa-file-contract"></i> Terms</a>
        <a href="/how-it-works.html"><i className="fas fa-play-circle"></i> How It Works</a>
        <a href="mailto:info@clickalinks.com"><i className="fas fa-envelope"></i> Contact</a>
      </div>
      {/* ... rest of footer ... */}
    </footer>
  );
};
